// Jernhusen omsättningsrapportering — login + POST /turnover/Create per verksamhet.
// ─────────────────────────────────────────────────────────────────────────────
// FYLL I DINA INLOGGNINGSUPPGIFTER HÄR (de två raderna):
const USER = 'tony@woso.se';          // ← ditt användarnamn
const PASS = 'SKRIV_DITT_LOSENORD';   // ← ditt lösenord
// ─────────────────────────────────────────────────────────────────────────────

const BASE = 'https://omsa.jernhusen.se';
const REPORT_URL = 'https://worder.woso.se/api/monthly-report?token=k742mDJ_HYrtZG-2qwRNAfev0a9u7qy4';

// shopId i worder-rapporten  →  Jernhusen BusinessId
const BUSINESSES = [
  { shopId: '67bc9ec96c7e0c3b0a59968f', businessId: 'c0f63bb3-eda4-44c0-8e3d-bd62d70edf4e', name: 'Woso Centralstationen' },
  { shopId: 'dinkassa-chao',            businessId: '4b7719f3-53a5-4882-b024-105953e8d2f1', name: 'Chao Oriental Express' },
];

const http = this.helpers.httpRequest;
const jar = {};
function addCookies(setCookie) {
  if (!setCookie) return;
  const arr = Array.isArray(setCookie) ? setCookie : [setCookie];
  for (const c of arr) { const p = c.split(';')[0]; const i = p.indexOf('='); if (i > 0) jar[p.slice(0,i).trim()] = p.slice(i+1); }
}
const cookieHeader = () => Object.entries(jar).map(([k,v]) => k+'='+v).join('; ');
function tokenFrom(html) { const m = /name="__RequestVerificationToken"[^>]*value="([^"]+)"/.exec(html||''); return m ? m[1] : null; }
const form = (obj) => Object.entries(obj).map(([k,v]) => encodeURIComponent(k)+'='+encodeURIComponent(v)).join('&');

if (!PASS || PASS === 'SKRIV_DITT_LOSENORD') throw new Error('Fyll i USER och PASS högst upp i Code-noden.');

// 1) Hämta månadens siffror
const report = await http({ url: REPORT_URL, json: true });
const [Year, Month] = report.month.split('-').map(Number);
const byId = Object.fromEntries(report.shops.map(s => [s.shopId, s]));

// 2) Login GET → token + cookie
const lg = await http({ url: BASE + '/Account/Login', returnFullResponse: true });
addCookies(lg.headers['set-cookie']);
const loginToken = tokenFrom(lg.body);

// 3) Login POST
const lp = await http({
  method: 'POST', url: BASE + '/Account/Login', returnFullResponse: true,
  headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Cookie': cookieHeader() },
  body: form({ __RequestVerificationToken: loginToken, Username: USER, Password: PASS, RememberMe: 'false' }),
});
addCookies(lp.headers['set-cookie']);

// 4) Per verksamhet: GET create (nytt token) → POST create
const results = [];
for (const b of BUSINESSES) {
  const shop = byId[b.shopId];
  if (!shop || shop.salesNet == null) { results.push({ name: b.name, status: 'skip', reason: 'saknar netto' }); continue; }
  const gc = await http({ url: BASE + '/turnover/Create?BusinessId=' + b.businessId, returnFullResponse: true, headers: { 'Cookie': cookieHeader() } });
  addCookies(gc.headers['set-cookie']);
  if (/name="Username"/.test(gc.body)) { results.push({ name: b.name, status: 'error', reason: 'inte inloggad (kontrollera USER/PASS)' }); continue; }
  const formToken = tokenFrom(gc.body);
  const pc = await http({
    method: 'POST', url: BASE + '/turnover/Create', returnFullResponse: true, headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Cookie': cookieHeader() },
    body: form({ __RequestVerificationToken: formToken, BusinessId: b.businessId, Year: Year, Month: Month, MonthlyTurnOverExVat: Math.round(shop.salesNet), NumberOfReceipts: shop.orders || 0, Comment: '' }),
  });
  const ok = pc.statusCode >= 200 && pc.statusCode < 400 && !/name="Username"/.test(pc.body || '');
  results.push({ name: b.name, status: ok ? 'ok' : 'error', code: pc.statusCode, exVat: Math.round(shop.salesNet), receipts: shop.orders || 0 });
}
return [{ json: { month: report.month, results } }];
